import java.util.TreeSet;

public class Solution {
    public static long solve(String s, long[] order, long k) {
        int n = s.length();
        TreeSet<Integer> stars = new TreeSet<>();
        long sum_invalid = n * (n + 1) / 2;
        long total_substrings = n * (n + 1) / 2;

        for (int t = 0; t < n; t++) {
            int pos = (int) order[t];
            Integer left = stars.floor(pos);
            Integer right = stars.ceil(pos);

            long right_val = (right == null) ? n : right;
            long left_val = (left == null) ? -1 : left;
            long original_length = right_val - left_val - 1;
            long original_contribution = original_length * (original_length + 1) / 2;

            long new_contribution = 0;

            if (left != null) {
                long left_part_length = pos - left - 1;
                if (left_part_length > 0) {
                    new_contribution += left_part_length * (left_part_length + 1) / 2;
                }
            }

            if (right != null) {
                long right_part_length = right - pos - 1;
                if (right_part_length > 0) {
                    new_contribution += right_part_length * (right_part_length + 1) / 2;
                }
            }

            sum_invalid = sum_invalid - original_contribution + new_contribution;
            stars.add(pos);

            long current_valid = total_substrings - sum_invalid;
            if (current_valid >= k) {
                return t;
            }
        }
        return -1;
    }
}
